app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});
```

---

### **4. ⚠️ ISSUE: Missing HTTPS & Security Headers**

**Problem:** No security headers configured; HTTP is used by default.

**Recommendation:**
```javascript
const express = require('express');
const helmet = require('helmet'); // npm install helmet
const app = express();

// Use Helmet to set security headers
app.use(helmet()); // Sets X-Frame-Options, X-Content-Type-Options, etc.

// Add additional security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  next();
});

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});
```

---

### **5. ⚠️ ISSUE: No Rate Limiting**

**Problem:** Endpoints can be abused through brute force or DoS attacks.

**Recommendation:**
```javascript
const rateLimit = require('express-rate-limit'); // npm install express-rate-limit

// Rate limiter
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
});

// Apply to all routes
app.use(limiter);

// Stricter limit for sensitive endpoints
const strictLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5, // 5 requests per 15 minutes
});

app.post('/login', strictLimiter, (req, res) => {
  // Login logic
});
```

---

### **6. ⚠️ ISSUE: No CORS Configuration**

**Problem:** CORS is not explicitly configured, could allow unauthorized cross-origin requests.

**Recommendation:**
```javascript
const cors = require('cors'); // npm install cors

const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
  optionsSuccessStatus: 200,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
};

app.use(cors(corsOptions));
```

---

### **7. ⚠️ ISSUE: No Request Logging or Monitoring**

**Problem:** No audit trail for debugging or security incidents.

**Recommendation:**
```javascript
const morgan = require('morgan'); // npm install morgan

// Log HTTP requests
app.use(morgan('combined')); // Combined Apache format for production

// Or use structured logging
app.use(morgan(':remote-addr - :remote-user [:date[clf]] ":method :url HTTP/:http-version" :status :res[content-length] - :response-time ms'));
```

---

### **8. ⚠️ ISSUE: Hardcoded Secrets & Port**

**Problem:** No environment variable configuration; secrets would be hardcoded.

**Recommendation:**
```javascript
require('dotenv').config(); // npm install dotenv

const express = require('express');
const app = express();

const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

app.get('/health', (req, res) => {
  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    environment: NODE_ENV 
  });
});

// Never expose sensitive data
if (NODE_ENV === 'production') {
  // Hide stack traces
  app.use((err, req, res, next) => {
    res.status(500).json({ error: 'Internal Server Error' });
  });
}

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

---

### **9. ⚠️ ISSUE: No Error Handling**

**Problem:** Unhandled exceptions could leak sensitive information.

**Recommendation:**
```javascript
// Global error handler
app.use((err, req, res, next) => {
  console.error('Error:', err); // Log for debugging

  // Don't expose internal error details in production
  if (process.env.NODE_ENV === 'production') {
    return res.status(500).json({ error: 'Internal Server Error' });
  }

  res.status(err.status || 500).json({
    error: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
  });
});
```

---

### **10. ⚠️ ISSUE: No Content Security Policy (CSP)**

**Problem:** Vulnerable to XSS attacks if HTML is served.

**Recommendation:**
```javascript
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: ["'self'", "'unsafe-inline'"], // Avoid unsafe-inline
    styleSrc: ["'self'", "'unsafe-inline'"],
    imgSrc: ["'self'", 'data:', 'https:'],
  },
}));
```

